import{_ as o,y as p,a as r,o as e,ag as g,D as c,g as h,I as t}from"./chunks/framework.RVu0gECZ.js";const T=JSON.parse('{"title":"Đặt hàng nhanh","description":"","frontmatter":{},"headers":[],"relativePath":"b2b-ecommerce-platform/quick-order.md","filePath":"b2b-ecommerce-platform/quick-order.md","lastUpdated":1775726513000}'),s={name:"b2b-ecommerce-platform/quick-order.md"};function i(m,n,l,u,d,b){const a=p("ImagePopup");return e(),r("div",null,[n[0]||(n[0]=g(`<h1 id="đat-hang-nhanh" tabindex="-1">Đặt hàng nhanh <a class="header-anchor" href="#đat-hang-nhanh" aria-label="Permalink to &quot;Đặt hàng nhanh&quot;">​</a></h1><p>Tính năng Đặt hàng nhanh cho phép các công ty thêm nhiều sản phẩm vào giỏ hàng của họ ngay lập tức bằng cách sử dụng SKU sản phẩm hoặc bằng cách tải lên tệp CSV.</p><p>Nó giúp tiết kiệm thời gian khi mua số lượng lớn hoặc mua lặp lại bằng cách đơn giản hóa quy trình lựa chọn sản phẩm.</p><h3 id="cac-buoc-su-dung-đat-hang-nhanh" tabindex="-1">Các bước sử dụng Đặt hàng nhanh <a class="header-anchor" href="#cac-buoc-su-dung-đat-hang-nhanh" aria-label="Permalink to &quot;Các bước sử dụng Đặt hàng nhanh&quot;">​</a></h3><p>Đi tới <strong>Tài khoản của tôi → Hồ sơ → Đơn hàng nhanh</strong> từ cửa hàng công ty.</p><p>Trang Đặt hàng nhanh sẽ xuất hiện, cho phép bạn tìm kiếm sản phẩm, nhập SKU hoặc tải lên file để đặt hàng số lượng lớn nhanh chóng.</p><p><strong>Tùy chọn có sẵn:</strong></p><p><strong>1) Tìm kiếm sản phẩm theo SKU hoặc Tên –</strong> Nhập SKU hoặc tên của sản phẩm để định vị sản phẩm đó một cách nhanh chóng.</p><p><strong>2) Nhập nhiều SKU –</strong> Thêm nhiều SKU cùng một lúc bằng cách phân tách chúng bằng dấu phẩy.</p><p><strong>3) Tải tệp lên –</strong> Tải lên tệp CSV để thêm nhiều sản phẩm cùng một lúc.</p><p><strong>4) Các định dạng được hỗ trợ –</strong> Chỉ hỗ trợ tệp CSV. Các cột nên bao gồm:</p><pre><code>- SKU – Mã sản phẩm

- Quantity – Số lượng cần bổ sung
</code></pre><p><strong>5) Tải xuống tệp mẫu –</strong> Tải xuống tệp CSV mẫu để tham khảo trước khi tải lên tệp của riêng bạn.</p>`,13)),c(a,{src:"/images/b2b-ecommerce-platform/1-quick-order.png",alt:"Super Admin Login"}),n[1]||(n[1]=h("h3",{id:"ssan-pham-đuoc-chon",tabindex:"-1"},[t("SSản phẩm được chọn "),h("a",{class:"header-anchor",href:"#ssan-pham-đuoc-chon","aria-label":'Permalink to "SSản phẩm được chọn"'},"​")],-1)),n[2]||(n[2]=h("p",null,"Sau khi nhập SKU vào trường, sản phẩm được liên kết với SKU đó sẽ được hiển thị.",-1)),n[3]||(n[3]=h("p",null,[t("Nhấp vào nút "),h("strong",null,"Thêm vào danh sách"),t(" và sản phẩm sẽ được thêm vào phần Sản phẩm đã chọn.")],-1)),c(a,{src:"/images/b2b-ecommerce-platform/2-selected-products.png",alt:"Super Admin Login"}),n[4]||(n[4]=h("p",null,[t("Khi bạn đã xem lại các sản phẩm đã chọn, hãy nhấp vào "),h("strong",null,"Thêm vào giỏ hàng"),t(" để chuyển chúng trực tiếp vào giỏ hàng của bạn để thanh toán.")],-1)),n[5]||(n[5]=h("p",null,"Tính năng này cho phép các công ty đặt hàng số lượng lớn một cách nhanh chóng và hiệu quả, loại bỏ nhu cầu duyệt qua nhiều trang sản phẩm.",-1))])}const k=o(s,[["render",i]]);export{T as __pageData,k as default};
